+import { Sprite, Texture, Rectangle } from 'pixi.js';
+
+type CharacterRole = 'king' | 'knight' | 'scribe';
+
+interface IdleFrame {
+  texture: Texture;
+  duration: number; // ms
+}
+
+export class CharacterIdleAnimation {
+  private frames: IdleFrame[];
+  private currentFrameIndex: number;
+  private elapsedTime: number;
+  private sprite: Sprite;
+  private loop: boolean;
+
+  constructor(role: CharacterRole, textureAtlas: Texture) {
+    this.frames = [];
+    this.currentFrameIndex = 0;
+    this.elapsedTime = 0;
+    this.loop = true;
+    this.sprite = new Sprite();
+
+    this.loadFrames(role, textureAtlas);
+    this.sprite.texture = this.frames[0].texture;
+  }
+
+  private loadFrames(role: CharacterRole, atlas: Texture) {
+    // Each spritesheet is 4 frames horizontally, each frame 64x64 px
+    const frameWidth = 64;
+    const frameHeight = 64;
+    for (let i = 0; i < 4; i++) {
+      const frameRect = new Rectangle(i * frameWidth, 0, frameWidth, frameHeight);
+      const frameTexture = new Texture(atlas.baseTexture, frameRect);
+      this.frames.push({ texture: frameTexture, duration: 250 }); // 250ms per frame for smooth loop
+    }
+  }
+
+  public update(deltaMS: number) {
+    this.elapsedTime += deltaMS;
+    const currentFrame = this.frames[this.currentFrameIndex];
+    if (this.elapsedTime >= currentFrame.duration) {
+      this.elapsedTime -= currentFrame.duration;
+      this.currentFrameIndex++;
+      if (this.currentFrameIndex >= this.frames.length) {
+        if (this.loop) {
+          this.currentFrameIndex = 0;
+        } else {
+          this.currentFrameIndex = this.frames.length - 1;
+        }
+      }
+      this.sprite.texture = this.frames[this.currentFrameIndex].texture;
+    }
+  }
+
+  public getSprite(): Sprite {
+    return this.sprite;
+  }
+}
